import { G, T, A, O, P } from './domains.js';

export const part1 = [
  {id:1,domain:G,question:"Which cryptographic algorithm is asymmetric?",options:["RSA","AES","Blowfish","3DES"],answer:0,explanation:"RSA uses a public/private key pair (asymmetric). The others are all symmetric.",optionExplanations:["RSA is asymmetric, using a public key to encrypt and a private key to decrypt.","AES is a symmetric block cipher using the same key to encrypt and decrypt.","Blowfish is a symmetric block cipher, not asymmetric.","3DES is a symmetric cipher applying DES three times."]},
  {id:2,domain:G,question:"What does AAA stand for in network security?",options:["Authentication, Authorization, Accounting","Authentication, Access, Accountability","Access, Authentication, Auditing","Authorization, Accounting, Auditing"],answer:0,explanation:"AAA = Authentication (verify identity), Authorization (grant access), Accounting (track activity).",optionExplanations:["Correct. AAA covers verifying identity, granting access, and logging activity.","Incorrect. Accountability is related but not the third A in AAA.","Incorrect. Access and Auditing are not the standard AAA terms.","Incorrect. The first A in AAA is Authentication, not Authorization."]},
  {id:3,domain:G,question:"Which principle limits users to only the permissions required for their job?",options:["Job rotation","Separation of duties","Least privilege","Need to know"],answer:2,explanation:"Least privilege restricts access to the minimum needed, reducing attack surface.",optionExplanations:["Job rotation moves employees through roles to detect fraud, not to limit permissions.","Separation of duties requires multiple people for a task, not limiting one person's access.","Least privilege grants only the minimum access needed to do the job.","Need to know is about information access, not the general permission-minimization term."]},
  {id:4,domain:G,question:"Which hashing algorithm produces a 256-bit digest?",options:["SHA-512","SHA-1","MD5","SHA-256"],answer:3,explanation:"SHA-256 produces a 256-bit hash. MD5=128-bit, SHA-1=160-bit, SHA-512=512-bit.",optionExplanations:["SHA-512 produces a 512-bit digest.","SHA-1 produces a 160-bit digest and is deprecated.","MD5 produces a 128-bit digest and is broken.","SHA-256 produces exactly a 256-bit output."]},
  {id:5,domain:G,question:"What is the primary purpose of a digital certificate?",options:["Secure key storage in a hardware vault","Binding a public key to an identity","Encrypting data at rest","Deriving a shared secret via Diffie-Hellman"],answer:1,explanation:"A digital certificate binds a public key to an identity, verified by a CA.",optionExplanations:["This describes a hardware security module (HSM), not a certificate.","Correct — a certificate binds a public key to a verified identity.","This describes disk or file encryption, not a certificate's purpose.","This describes a Diffie-Hellman key exchange, not a certificate."]},
  {id:6,domain:G,question:"Which protocol provides secure remote command-line access?",options:["Telnet","SSH","FTP","RDP"],answer:1,explanation:"SSH (port 22) encrypts remote shell sessions. Telnet and FTP are unencrypted.",optionExplanations:["Telnet transmits data, including credentials, in plaintext.","SSH encrypts the entire session, providing secure remote CLI access.","FTP does not provide command-line access and is unencrypted.","RDP provides graphical remote desktop access, not a CLI."]},
  {id:7,domain:G,question:"A user must present a password AND a fingerprint to log in. This is an example of:",options:["Role-based access control","Federated identity","Two-factor authentication","Single-factor authentication"],answer:2,explanation:"Using two different factor types (something you know + something you are) = MFA/2FA.",optionExplanations:["RBAC assigns permissions by role; it is not an authentication mechanism.","Federated identity authenticates across organizations via a shared identity provider.","Correct — password (knowledge) plus fingerprint (biometric) are two distinct factors.","Single-factor authentication uses only one form of verification."]},
  {id:8,domain:G,question:"Which type of security control is an antivirus program?",options:["Detective","Corrective","Preventive","Deterrent"],answer:2,explanation:"Antivirus prevents malware from executing, so it is primarily a preventive control.",optionExplanations:["Detective controls identify threats after the fact, like IDS alerts.","Corrective controls restore systems after an incident.","Correct — antivirus blocks malware from executing before it runs.","Deterrent controls discourage attacks through visible presence or warnings."]},
  {id:9,domain:G,question:"What does PKI stand for?",options:["Public Key Infrastructure","Private Key Integration","Public Knowledge Interface","Protected Key Index"],answer:0,explanation:"PKI = Public Key Infrastructure — the framework of CAs, certificates, and policies for managing public keys.",optionExplanations:["Correct — PKI manages digital certificates and public key encryption.","Private Key Integration is not a real cryptography term.","Public Knowledge Interface is not a recognized security acronym.","Protected Key Index is not an established security framework."]},
  {id:10,domain:G,question:"Which of the following best describes a Certificate Authority (CA)?",options:["A trusted entity that issues digital certificates","A protocol for key exchange","A server that stores encrypted passwords","A firewall that filters encrypted traffic"],answer:0,explanation:"A CA is a trusted third party that signs and issues digital certificates.",optionExplanations:["Correct — a CA verifies identities and signs certificates.","Key exchange is handled by protocols like Diffie-Hellman, not a CA.","Password storage is handled by identity providers, not a CA.","Firewalls filter traffic by port or protocol, not certificates."]},
  {id:11,domain:G,question:"Which of the following is an example of 'something you have' in MFA?",options:["Smart card","Fingerprint","Security question","Password"],answer:0,explanation:"'Something you have' is a physical token or device, like a smart card or hardware key.",optionExplanations:["Correct — a smart card is a physical possession factor.","A fingerprint is 'something you are,' the biometric factor.","A security question is 'something you know,' not possession.","A password is 'something you know,' the knowledge factor."]},
  {id:12,domain:G,question:"What is the purpose of a salt in password hashing?",options:["Prevent rainbow table attacks","Replace the need for hashing","Encrypt the password database","Speed up the hashing process"],answer:0,explanation:"A salt is random data added before hashing; it makes precomputed rainbow table attacks infeasible.",optionExplanations:["Correct — a unique salt per password defeats precomputed rainbow tables.","Salting works alongside hashing; it does not replace it.","Salting does not encrypt the database; that is a separate control.","Salting adds slight overhead; it does not speed up hashing."]},
  {id:13,domain:G,question:"Which access control model uses sensitivity labels and clearances?",options:["Attribute-Based Access Control (ABAC)","Mandatory Access Control (MAC)","Discretionary Access Control (DAC)","Role-Based Access Control (RBAC)"],answer:1,explanation:"MAC uses sensitivity labels (e.g., Top Secret) matched against user clearances, enforced by the OS.",optionExplanations:["ABAC evaluates attributes dynamically, not fixed clearance levels.","Correct — MAC enforces access via classification labels and clearances.","DAC lets resource owners set permissions, not labels or clearances.","RBAC assigns permissions to roles, not classification labels."]},
  {id:14,domain:G,question:"What is the difference between symmetric and asymmetric encryption?",options:["Asymmetric is faster for bulk data encryption","Symmetric uses one key; asymmetric uses two","Symmetric uses two different keys","Symmetric is slower than asymmetric"],answer:1,explanation:"Symmetric: one shared secret key. Asymmetric: public/private key pair. Symmetric is faster for bulk data.",optionExplanations:["Asymmetric is actually too slow for bulk data; symmetric is used instead.","Correct — symmetric shares one key, asymmetric uses a public/private pair.","This describes asymmetric encryption, not symmetric.","Symmetric encryption is actually faster than asymmetric."]},
  {id:15,domain:G,question:"Which protocol is used to authenticate users to a network using tickets?",options:["LDAP","TACACS+","RADIUS","Kerberos"],answer:3,explanation:"Kerberos uses a Key Distribution Center (KDC) to issue tickets for network authentication.",optionExplanations:["LDAP is a directory protocol, not a ticket-based authentication system.","TACACS+ separates AAA functions but does not use tickets.","RADIUS provides centralized authentication but does not use tickets.","Correct — Kerberos issues tickets via a Key Distribution Center."]},
  {id:16,domain:G,question:"A security team implements a policy requiring two employees to authorize financial transfers. This is an example of:",options:["Separation of duties","Least privilege","Need to know","Mandatory vacation"],answer:0,explanation:"Separation of duties splits critical tasks between two or more people to prevent fraud.",optionExplanations:["Correct — separation of duties splits a task between two people.","Least privilege limits individual permissions, not requiring two approvers.","Need to know restricts access to information, not transaction approval.","Mandatory vacation forces leave so irregularities can be detected."]},
  {id:17,domain:G,question:"Which of the following is a stream cipher?",options:["Blowfish","RC4","3DES","AES"],answer:1,explanation:"RC4 is a stream cipher. AES, 3DES, and Blowfish are all block ciphers.",optionExplanations:["Blowfish is a block cipher, not a stream cipher.","Correct — RC4 encrypts data one byte at a time as a stream cipher.","3DES is a block cipher based on DES.","AES is a block cipher operating on 128-bit blocks."]},
  {id:18,domain:G,question:"What term describes the concept that data should only be modified by authorized parties?",options:["Non-repudiation","Confidentiality","Availability","Integrity"],answer:3,explanation:"Integrity ensures data is accurate and has not been tampered with by unauthorized parties.",optionExplanations:["Non-repudiation proves origin so a sender cannot deny an action.","Confidentiality prevents disclosure to unauthorized parties, not modification.","Availability ensures systems and data are accessible when needed.","Correct — integrity means data remains accurate and unaltered."]},
  {id:19,domain:G,question:"Which key exchange algorithm allows two parties to establish a shared secret over an insecure channel?",options:["SHA-256","RSA","AES","Diffie-Hellman"],answer:3,explanation:"Diffie-Hellman enables two parties to derive the same shared secret without transmitting it directly.",optionExplanations:["SHA-256 is a hash function, not a key exchange algorithm.","RSA can exchange keys but by encrypting them, not deriving them jointly.","AES is a symmetric cipher, not a key exchange mechanism.","Correct — Diffie-Hellman lets both parties derive the same secret."]},
  {id:20,domain:G,question:"What type of certificate is used to secure multiple subdomains under a single domain?",options:["Root certificate","Self-signed certificate","Wildcard certificate","Code signing certificate"],answer:2,explanation:"A wildcard certificate (*.example.com) covers all immediate subdomains of a domain.",optionExplanations:["A root certificate belongs to a CA and signs other certificates.","Self-signed certificates are not trusted by default by browsers.","Correct — a wildcard certificate uses an asterisk to cover all subdomains.","Code signing certificates verify software publishers, not websites."]},
  {id:21,domain:G,question:"Which of the following best describes non-repudiation?",options:["Ensuring systems stay continuously available","Preventing a sender from denying a message","Requiring two authentication factors at login","Encrypting data while in transit"],answer:1,explanation:"Non-repudiation provides cryptographic proof of origin so a sender cannot deny an action.",optionExplanations:["This describes availability, not non-repudiation.","Correct — non-repudiation proves origin so a sender can't deny an action.","This describes multi-factor authentication, not non-repudiation.","This describes confidentiality in transit, not proof of origin."]},
  {id:22,domain:G,question:"A company stores passwords using bcrypt. What advantage does bcrypt offer over MD5?",options:["Shorter hash output than MD5","A symmetric encryption cipher","Eliminates the need for salting","Deliberately slow with a work factor"],answer:3,explanation:"Bcrypt is designed to be computationally expensive; its work factor can be increased over time to resist brute force.",optionExplanations:["Bcrypt actually produces longer output; its advantage is computational cost.","Bcrypt is a hashing function, not a symmetric cipher.","Bcrypt auto-generates a salt but doesn't eliminate salting as a concept.","Correct — the work factor makes bcrypt slow, resisting brute force."]},
  {id:23,domain:G,question:"Which protocol does 802.1X use for authentication?",options:["Kerberos","TACACS+","RADIUS","LDAP"],answer:2,explanation:"802.1X is a port-based NAC standard that typically uses RADIUS as the backend authentication server.",optionExplanations:["Kerberos issues domain tickets but isn't the 802.1X backend.","TACACS+ is used mainly for device administration, not 802.1X.","Correct — RADIUS is the standard backend for 802.1X network access.","LDAP is a directory protocol, not the 802.1X backend."]},
  {id:24,domain:G,question:"What type of control is a security guard at a data center entrance?",options:["Physical","Administrative","Compensating","Technical"],answer:0,explanation:"A security guard is a physical control — a human presence to control physical access.",optionExplanations:["Correct — a guard is a physical control protecting facility access.","Administrative controls are policies, procedures, and training.","Compensating controls substitute for a control that can't be implemented.","Technical controls are implemented via technology like firewalls or IDS."]},
  {id:25,domain:G,question:"Which of the following is an example of a compensating control?",options:["Annual phishing awareness training","Adding MFA to compensate for weak passwords","Full-disk encryption on laptops","A firewall rule blocking port 80"],answer:1,explanation:"A compensating control substitutes for a required control that cannot be fully implemented.",optionExplanations:["This is an administrative preventive control, not a compensating one.","Correct — MFA compensates for a password policy that alone isn't strong enough.","This is a primary preventive control, not a substitute for another.","This is a primary preventive control, not a substitute for another."]},
  {id:26,domain:G,question:"Which encryption mode turns a block cipher into a stream cipher?",options:["CBC","GCM","ECB","CTR"],answer:3,explanation:"Counter (CTR) mode uses an incrementing counter to generate a keystream, converting a block cipher to stream-like operation.",optionExplanations:["CBC chains blocks together; it is still block-by-block.","GCM adds authentication but is also based on counter mode.","ECB encrypts each block independently, revealing patterns.","Correct — CTR mode generates a keystream, acting like a stream cipher."]},
  {id:27,domain:G,question:"What is the purpose of a hardware security module (HSM)?",options:["Scanning endpoints for malware","Monitoring traffic for attack signatures","Securely generating and storing cryptographic keys","Authenticating VPN users via RADIUS"],answer:2,explanation:"An HSM is a dedicated physical device for cryptographic key management and operations.",optionExplanations:["This describes antivirus or EDR, not an HSM.","This describes an IDS/IPS, not an HSM.","Correct — an HSM is a dedicated device for key generation and storage.","This describes a AAA/RADIUS setup, not an HSM."]},
  {id:28,domain:G,question:"Which protocol secures email in transit between mail servers?",options:["STARTTLS","S/MIME","PGP","DMARC"],answer:0,explanation:"STARTTLS upgrades a plain SMTP connection to TLS encryption between mail servers.",optionExplanations:["Correct — STARTTLS upgrades SMTP connections to TLS between mail servers.","S/MIME encrypts individual messages end-to-end, not server-to-server transport.","PGP encrypts message content between users, not transport itself.","DMARC prevents spoofing; it does not encrypt traffic."]},
  {id:29,domain:G,question:"What is the function of OCSP?",options:["Distributing certificates via a directory","Checking whether a certificate is revoked","Encrypting and signing email messages","Generating time-based one-time passwords"],answer:1,explanation:"OCSP (Online Certificate Status Protocol) allows clients to check in real time if a certificate is revoked.",optionExplanations:["This describes LDAP-based certificate distribution, not OCSP.","Correct — OCSP checks certificate revocation status in real time.","This describes S/MIME or PGP, not OCSP.","This describes TOTP, not OCSP."]},
  {id:30,domain:G,question:"Which of the following describes role-based access control (RBAC)?",options:["Access based on user attributes and environment","Access based on data classification labels","Access based on job function","Access decisions made by the resource owner"],answer:2,explanation:"RBAC assigns permissions to roles (e.g., Manager, Admin), and users are placed in roles.",optionExplanations:["Attribute-based decisions describe ABAC.","Access based on classification labels describes MAC.","Correct — RBAC grants permissions aligned with job functions.","Resource owner-controlled access describes DAC."]},
  {id:31,domain:G,question:"Which wireless security protocol replaced WPA2 and added stronger encryption?",options:["WEP","WPA3","802.11ac","WPA"],answer:1,explanation:"WPA3 introduced SAE (Simultaneous Authentication of Equals) and stronger 192-bit encryption for enterprise.",optionExplanations:["WEP is the oldest, most insecure wireless protocol.","Correct — WPA3 adds SAE and stronger encryption for enterprise.","802.11ac is a Wi-Fi speed standard, not a security protocol.","WPA was a temporary fix for WEP and has been superseded."]},
  {id:32,domain:G,question:"What does TLS provide that SSL does not?",options:["Port-based network access control","Stronger cipher suites and security fixes","Encryption between client and server","Certificate-based server authentication"],answer:1,explanation:"TLS is the successor to SSL with improved cipher suites, fixed vulnerabilities, and deprecated weak algorithms.",optionExplanations:["This describes 802.1X, unrelated to TLS or SSL.","Correct — TLS improved cipher suites and fixed SSL's flaws.","Both TLS and SSL provide encryption; this isn't unique to TLS.","Both TLS and SSL support certificate-based authentication."]},
  {id:33,domain:G,question:"Which term describes a vulnerability that is unknown to the vendor and has no patch?",options:["Legacy vulnerability","Common vulnerability","Zero-day","Known exploit"],answer:2,explanation:"A zero-day vulnerability is unknown to the vendor; there is no patch available at the time of discovery.",optionExplanations:["Legacy vulnerabilities exist in outdated, possibly unsupported software.","A common vulnerability implies known CVEs already reported to the vendor.","Correct — a zero-day is unknown to the vendor, so no patch exists.","A known exploit is documented, usually after a patch exists."]},
  {id:34,domain:G,question:"Which of the following BEST describes data integrity?",options:["Data remains accurate and unaltered","Encrypting data in transit","Restricting data to authorized users","Data remains accessible when needed"],answer:0,explanation:"Integrity = data has not been tampered with and remains accurate and consistent.",optionExplanations:["Correct — integrity means data is accurate and unaltered.","This describes confidentiality in transit, not integrity.","This describes confidentiality, not integrity.","This describes availability, not integrity."]},
  {id:35,domain:G,question:"A web application uses HTTPS. Which layer does TLS operate at?",options:["Data link layer","Network layer","Transport layer","Application layer"],answer:2,explanation:"TLS operates at the Transport layer (Layer 4) of the OSI model, encrypting the session.",optionExplanations:["The data link layer handles MAC addressing, not TLS.","The network layer handles IP routing; TLS is not here.","Correct — TLS operates at the Transport layer, encrypting the session.","HTTP operates at the application layer; TLS secures it from below."]},
  {id:36,domain:G,question:"Which authentication factor is a retina scan?",options:["Something you are","Something you have","Something you know","Somewhere you are"],answer:0,explanation:"Biometric factors like retina scans are 'something you are' — inherence factors.",optionExplanations:["Correct — a retina scan is a biometric, inherence factor.","Something you have includes smart cards and tokens.","Something you know includes passwords and PINs.","Somewhere you are is a location factor like GPS."]},
  {id:37,domain:G,question:"What is the purpose of key escrow?",options:["A trusted third party holds key copies","Hashing passwords for storage","Publishing certificates to a directory","Deriving a session key via Diffie-Hellman"],answer:0,explanation:"Key escrow allows a trusted third party (e.g., law enforcement or recovery agent) to access encryption keys when needed.",optionExplanations:["Correct — key escrow lets a trusted third party access keys for recovery.","This describes password hashing, not key escrow.","This describes PKI certificate distribution, not key escrow.","This describes TLS key exchange, not key escrow."]},
  {id:38,domain:G,question:"Which of the following is true about elliptic curve cryptography (ECC)?",options:["Requires larger keys than RSA","Used only for key exchange","Equivalent security to RSA with smaller keys","A symmetric encryption algorithm"],answer:2,explanation:"ECC provides the same security as RSA with significantly shorter keys, making it efficient for mobile and IoT.",optionExplanations:["ECC actually needs much smaller keys than RSA for equivalent security.","ECC supports both digital signatures and key exchange.","Correct — ECC matches RSA's security with far smaller keys.","ECC is asymmetric, using a public/private key pair."]},
  {id:39,domain:G,question:"What type of attack specifically targets the weakest link in the security chain — humans?",options:["Zero-day attack","SQL injection","Buffer overflow","Social engineering"],answer:3,explanation:"Social engineering manipulates people rather than exploiting technical vulnerabilities.",optionExplanations:["Zero-day attacks exploit unknown software vulnerabilities, not human behavior.","SQL injection is a technical attack against databases.","Buffer overflow exploits memory management flaws in code.","Correct — social engineering exploits human psychology to gain access."]},
  {id:40,domain:G,question:"Which of the following is an administrative security control?",options:["Security policy","Firewall","Antivirus software","CCTV camera"],answer:0,explanation:"Administrative controls are policies, procedures, and guidelines — management-level controls.",optionExplanations:["Correct — a security policy is an administrative control defining behavior rules.","A firewall is a technical control implemented through technology.","Antivirus software is a technical control deployed on endpoints.","CCTV is a physical control used for monitoring."]},
  {id:41,domain:G,question:"What is perfect forward secrecy (PFS)?",options:["A unique ephemeral key per session","Archiving session keys in an HSM","Reusing one long-term key for all sessions","Encrypting each payload with two keys"],answer:0,explanation:"PFS generates a new ephemeral key pair for each session, so compromising one key does not expose past sessions.",optionExplanations:["Correct — a fresh ephemeral key per session protects past sessions if a key leaks.","Archiving keys is the opposite of PFS, which avoids storing session keys.","Reusing one key for all sessions is the opposite of PFS.","This describes layered or double encryption, not PFS."]},
  {id:42,domain:G,question:"Which of the following is NOT a property of a secure hash function?",options:["Fixed-length output","Reversible","Deterministic output","Collision resistant"],answer:1,explanation:"Hashing is a one-way function; it cannot be reversed. This is a fundamental property.",optionExplanations:["Fixed-length output regardless of input size is a required hash property.","Correct — reversibility would make it encryption, not hashing.","Deterministic output is a required hash property.","Collision resistance means two inputs rarely produce the same hash."]},
  {id:43,domain:G,question:"A certificate is revoked before its expiration date. Which mechanism provides the most current revocation status?",options:["LDAP","CRL","DNS","OCSP"],answer:3,explanation:"OCSP provides real-time certificate revocation status, while CRLs can be large and cached.",optionExplanations:["LDAP is a directory protocol, not revocation status.","CRLs are published periodically and may be stale.","DNS handles name resolution, not revocation status.","Correct — OCSP provides real-time, per-certificate revocation checking."]},
  {id:44,domain:G,question:"Which statement about symmetric encryption is correct?",options:["It is slower than asymmetric encryption","It uses separate keys for encryption and decryption","It is ideal for bulk data encryption","It provides built-in non-repudiation"],answer:2,explanation:"Symmetric encryption is fast and efficient, making it ideal for encrypting large amounts of data.",optionExplanations:["Symmetric encryption is actually faster than asymmetric.","Symmetric encryption uses the same key for both operations.","Correct — symmetric encryption's speed makes it ideal for bulk data.","Non-repudiation requires asymmetric digital signatures, not symmetric encryption."]},
  {id:45,domain:G,question:"Which of the following describes steganography?",options:["Striping data across multiple drives","Hiding data within another file","Encrypting plaintext into ciphertext","Cascading multiple encryption algorithms"],answer:1,explanation:"Steganography conceals the existence of data by hiding it within another file such as an image.",optionExplanations:["This describes RAID striping, not steganography.","Correct — steganography conceals data inside another file, like an image.","This describes standard encryption, not steganography.","This describes cascaded encryption, not steganography."]},
  {id:46,domain:G,question:"What does SAML provide in federated identity management?",options:["Encrypting passwords in transit","Passing authentication assertions to enable SSO","Managing X.509 certificate lifecycle","Capturing biometric data at login"],answer:1,explanation:"SAML (Security Assertion Markup Language) passes XML-based authentication assertions to enable SSO across organizations.",optionExplanations:["This is handled by HTTPS/TLS, not SAML.","Correct — SAML passes XML assertions between IdP and service provider for SSO.","This describes PKI certificate management, not SAML.","This happens at the identity provider, not via SAML itself."]},
  {id:47,domain:G,question:"Which of the following describes a man-in-the-middle (MITM) attack?",options:["Trying every possible password","Overwriting memory via a buffer","Intercepting communication between two parties","Flooding a target with traffic"],answer:2,explanation:"MITM attacks intercept communication between two parties, potentially reading or altering the data.",optionExplanations:["This describes a brute-force attack, not MITM.","This describes a buffer overflow, not MITM.","Correct — MITM intercepts or alters traffic between two parties.","This describes a DDoS attack, not MITM."]},
  {id:48,domain:G,question:"What is the primary purpose of a VPN?",options:["Absorbing traffic floods via scrubbing centers","Validating remote user certificates","Behavioral analysis of endpoint processes","Creating an encrypted tunnel over the internet"],answer:3,explanation:"A VPN creates an encrypted tunnel so traffic traversing an untrusted network (like the Internet) remains private.",optionExplanations:["This describes DDoS mitigation, not a VPN.","Certificate validation can be part of VPN auth, but it isn't the VPN's main purpose.","This describes EDR, not a VPN.","Correct — a VPN tunnels traffic securely over an untrusted network."]},
  {id:49,domain:G,question:"A developer uses HTTPS for a web app but the certificate is self-signed. What is the main risk?",options:["Server identity cannot be verified","Browsers reject the session cookies","Slower TLS handshake performance","Traffic remains unencrypted in transit"],answer:0,explanation:"Self-signed certificates encrypt traffic but are not trusted by browsers — users cannot verify the server's identity.",optionExplanations:["Correct — without a trusted CA signature, identity can't be verified.","Cookie handling depends on secure attributes, not CA trust.","Certificate type doesn't meaningfully affect handshake speed.","Self-signed certificates still encrypt traffic; only trust is missing."]},
  {id:50,domain:G,question:"Which of the following is the function of an IV (initialization vector) in encryption?",options:["Computing a keyed hash (MAC)","Randomizing output to prevent identical ciphertexts","A substitute for the encryption key","Secure storage for the decryption key"],answer:1,explanation:"An IV adds randomness so that identical plaintexts encrypted with the same key produce different ciphertexts.",optionExplanations:["This describes a MAC/HMAC, not an IV.","Correct — the IV randomizes output so identical plaintexts differ.","The IV is not a substitute for the key; both are separate inputs.","This describes an HSM or key store, not an IV."]},
  {id:51,domain:G,question:"Which of the following BEST describes a digital signature?",options:["Encrypting the message with the recipient's public key","Deriving a shared secret over a public channel","Generating a session key after the handshake","Encrypting a message hash with the sender's private key"],answer:3,explanation:"A digital signature = hash of message encrypted with sender's private key; recipient decrypts with sender's public key.",optionExplanations:["This provides confidentiality, not authentication of the sender.","This describes Diffie-Hellman key exchange, not a digital signature.","This describes TLS session key establishment, not signing.","Correct — signing encrypts the message hash with the sender's private key."]},
  {id:52,domain:G,question:"What is a CRL?",options:["A list of revoked certificates","A log of failed login attempts","A queue of pending certificate requests","A list of accepted cipher suites"],answer:0,explanation:"A Certificate Revocation List (CRL) is published by a CA listing certificates revoked before their expiry.",optionExplanations:["Correct — a CRL lists certificates revoked before expiration.","This describes authentication logs, not a CRL.","This describes a CA's request queue, not a CRL.","This describes a cipher suite configuration, not a CRL."]},
  {id:53,domain:G,question:"Which protocol provides centralized authentication, authorization, and accounting for network device administration?",options:["SAML","RADIUS","Kerberos","TACACS+"],answer:3,explanation:"TACACS+ separates authentication, authorization, and accounting and is commonly used for managing network devices.",optionExplanations:["SAML is an SSO/federation protocol for web apps, not device admin.","RADIUS combines AAA in one step, mainly for network access.","Kerberos uses tickets for domain auth, not device management.","Correct — TACACS+ separates AAA and is preferred for device administration."]},
  {id:54,domain:G,question:"What is the main difference between identification and authentication?",options:["They are the same process","Identification verifies; authentication claims","Identification claims identity; authentication verifies it","Authentication happens before identification"],answer:2,explanation:"Identification = claiming who you are (username); Authentication = proving it (password, biometric).",optionExplanations:["They are distinct steps: identify first, then prove it.","This reverses the definitions incorrectly.","Correct — identification claims identity, authentication verifies the claim.","Authentication always follows identification, not the reverse."]},
  {id:55,domain:G,question:"Which of the following is an example of a technical security control?",options:["Data encryption","Background checks","Acceptable use policy","Security awareness training"],answer:0,explanation:"Technical controls are implemented through technology: firewalls, encryption, IDS, access controls.",optionExplanations:["Correct — encryption is a technical control using cryptography.","Background checks are administrative (personnel) controls.","An acceptable use policy is an administrative control.","Security awareness training is an administrative control."]},
  {id:56,domain:G,question:"Which of the following is TRUE about WPA3 Enterprise?",options:["It uses TKIP for encryption","It requires 192-bit encryption","It is backward compatible with WEP","It uses a pre-shared key for authentication"],answer:1,explanation:"WPA3 Enterprise mandates a 192-bit security suite for the highest protection level.",optionExplanations:["WPA3 uses GCMP-256, replacing CCMP/AES and deprecated TKIP.","Correct — WPA3 Enterprise requires a 192-bit minimum security suite.","WEP is broken and has no compatibility with WPA3.","Pre-shared keys are used in WPA3 Personal, not Enterprise."]},
  {id:57,domain:G,question:"What does the term 'defense in depth' mean?",options:["Layering multiple overlapping security controls","Relying on one strong control alone","Encrypting data at every network hop","Requiring background checks for employees"],answer:0,explanation:"Defense in depth uses multiple overlapping security layers so an attacker must defeat several controls.",optionExplanations:["Correct — defense in depth layers multiple controls so no single failure is fatal.","Relying on a single control is the opposite of defense in depth.","This is one narrow tactic, not the broader layered strategy.","This is one administrative control, not the layered strategy itself."]},
  {id:58,domain:G,question:"Which port does HTTPS use by default?",options:["22","8080","80","443"],answer:3,explanation:"HTTPS (HTTP over TLS) runs on TCP port 443 by default.",optionExplanations:["Port 22 is reserved for SSH, not HTTPS.","Port 8080 is a common alternative HTTP port.","Port 80 is the default for unencrypted HTTP.","Correct — port 443 is the well-known port for HTTPS."]},
  {id:59,domain:G,question:"Which of the following BEST describes role-based access control?",options:["Based on combined user and resource attributes","The resource owner grants access","Based on data classification labels","Based on job function and role"],answer:3,explanation:"In RBAC, permissions are assigned to roles (e.g., HR, Finance) and users inherit permissions by being assigned a role.",optionExplanations:["This describes ABAC, not RBAC.","This describes DAC, not RBAC.","This describes MAC, not RBAC.","Correct — RBAC assigns permissions based on job roles."]},
  {id:60,domain:G,question:"Which of the following is a detective security control?",options:["Software blocking unauthorized data transfers","Encrypting sensitive data at rest","Reviewing camera footage after an incident","Installing locks on server room doors"],answer:2,explanation:"Detective controls identify incidents after they occur; reviewing camera footage to detect a breach is detective.",optionExplanations:["This describes DLP, a preventive control, not detective.","Encryption is a preventive control, not detective.","Correct — reviewing footage after the fact detects that an event occurred.","Locks are a preventive physical control, not detective."]},
  {id:61,domain:G,question:"What is the purpose of a nonce in cryptography?",options:["Deriving a public key from curve math","Long-term storage for symmetric keys","Ensuring a value is used only once","A substitute for the IV"],answer:2,explanation:"A nonce (number used once) prevents replay attacks by ensuring each request or session is unique.",optionExplanations:["This describes asymmetric key generation, not a nonce.","This describes a key management system, not a nonce.","Correct — a nonce is used once to prevent replay attacks.","A nonce and an IV serve related but distinct roles."]},
  {id:62,domain:G,question:"What distinguishes TOTP from HOTP?",options:["TOTP needs hardware; HOTP is software-only","TOTP uses a counter; HOTP uses time","TOTP is time-based; HOTP is counter-based","They always produce identical codes"],answer:2,explanation:"TOTP (Time-based OTP) rotates every 30 seconds. HOTP (HMAC-based OTP) increments a counter with each use.",optionExplanations:["Both can be implemented in hardware or software.","This reverses the definitions — TOTP is time-based, HOTP is counter-based.","Correct — TOTP rotates by time interval, HOTP by an event counter.","TOTP and HOTP use different mechanisms and produce different codes."]},
  {id:63,domain:G,question:"A company implements biometric authentication. Which of the following is a major concern?",options:["Requires constant cloud connectivity","Readers are too slow for enterprise use","Cannot be combined with MFA","Cannot be changed once compromised"],answer:3,explanation:"Unlike passwords, biometric traits (fingerprints, retinas) cannot be reissued if the stored template is breached.",optionExplanations:["Most biometric matching happens locally on-device, not in the cloud.","Modern biometric readers are fast and widely deployed without meaningful delay.","Biometrics are commonly combined with passwords or tokens in MFA.","Correct — unlike a password, a compromised biometric trait can't be reissued."]},
  {id:64,domain:G,question:"What does the term 'open authentication' (OAuth) primarily provide?",options:["Delegating access without sharing credentials","Encrypting password fields in transit","Requiring a second authentication factor","Managing X.509 certificate lifecycle"],answer:0,explanation:"OAuth allows a user to authorize a third-party app to access their resources without exposing their credentials.",optionExplanations:["Correct — OAuth issues tokens that grant limited access without exposing credentials.","This is handled by TLS, not OAuth.","This describes MFA, a separate mechanism from OAuth.","This describes PKI, not OAuth."]},
  {id:65,domain:G,question:"Which cipher mode provides both encryption and authentication?",options:["GCM","ECB","CTR","CBC"],answer:0,explanation:"GCM (Galois/Counter Mode) provides confidentiality (counter mode) and message authenticity (GHASH).",optionExplanations:["Correct — GCM combines CTR encryption with a GHASH authentication tag.","ECB encrypts blocks independently with no authentication.","CTR provides encryption but not built-in authentication.","CBC provides encryption but needs a separate MAC for authentication."]},
  {id:66,domain:G,question:"What is a PKI trust anchor?",options:["The root CA's inherently trusted certificate","An intermediate CA certificate","A hardware device storing private keys","A certificate issued to an end entity"],answer:0,explanation:"The root CA is the trust anchor; its self-signed certificate is explicitly trusted in certificate stores.",optionExplanations:["Correct — the root CA's self-signed certificate is the trust anchor.","An intermediate CA inherits trust; it isn't the anchor itself.","This describes an HSM, not a trust anchor.","Leaf certificates chain up to the anchor; they aren't the anchor."]},
  {id:67,domain:G,question:"Which of the following is a characteristic of attribute-based access control (ABAC)?",options:["Based on static classification labels","Based on predefined job roles","Evaluating user, resource, and environment attributes","Decided solely by the resource owner"],answer:2,explanation:"ABAC evaluates multiple attributes dynamically — user department, resource sensitivity, time of day, location, etc.",optionExplanations:["This describes MAC, not ABAC.","This describes RBAC, not ABAC.","Correct — ABAC evaluates multiple attributes dynamically.","This describes DAC, not ABAC."]},
  {id:68,domain:G,question:"Which of the following protocols encrypts the ENTIRE RADIUS packet, including the username?",options:["TACACS+","LDAP over TLS","RADIUS over TCP","RADIUS over UDP"],answer:0,explanation:"TACACS+ encrypts the entire packet body. RADIUS only encrypts the password field.",optionExplanations:["Correct — TACACS+ encrypts the entire packet payload.","LDAP over TLS is a directory protocol, not an AAA protocol.","RadSec encrypts everything, but standard TACACS+ is the expected answer.","Standard RADIUS over UDP encrypts only the password field."]},
  {id:69,domain:G,question:"What is the purpose of a cross-certification between two PKIs?",options:["Auto-revoking certificates across both CAs","Merging two CA hierarchies into one","Establishing mutual trust between two PKIs","Speeding up OCSP lookups"],answer:2,explanation:"Cross-certification creates mutual trust between separate PKI hierarchies so entities in each can validate the other's certificates.",optionExplanations:["Revocation is handled by CRLs/OCSP within each PKI, not by cross-certification.","Cross-certification creates trust without merging the hierarchies.","Correct — cross-certification establishes mutual trust between two PKIs.","Lookup speed depends on OCSP/CRL infrastructure, not cross-certification."]},
  {id:70,domain:G,question:"Which of the following describes a 'chain of trust' in PKI?",options:["Root CA through intermediates to end-entity certs","Encrypted tunnels between servers","A list of revoked certificates","A protocol verifying IP ownership"],answer:0,explanation:"The chain of trust links an end-entity certificate back to a trusted root CA via intermediate CAs.",optionExplanations:["Correct — the chain of trust links certificates from root to end entity.","This describes VPN/TLS tunnels, not the certificate hierarchy.","This describes a CRL, a separate PKI component.","This describes DNSSEC or BGP security, not PKI's chain of trust."]},
  {id:71,domain:G,question:"Which of the following is a feature of SSO (Single Sign-On)?",options:["One set of credentials grants access to multiple systems","Each system maintains its own password database","SSO eliminates the need for encryption","Users must log in separately to each system"],answer:0,explanation:"SSO lets users authenticate once and gain access to all connected systems without re-authenticating.",optionExplanations:["Correct — SSO authenticates once and grants access to connected systems.","With SSO, a central identity provider manages authentication instead.","SSO addresses authentication, not encryption; both coexist independently.","Logging in separately to each system is the problem SSO solves."]},
  {id:72,domain:G,question:"What is the purpose of a security token in authentication?",options:["Full-disk encryption for stored files","Replacing all biometric authentication factors","Inspecting packets for intrusion attempts","Generating or storing one-time passwords"],answer:3,explanation:"Security tokens (hardware or software) generate OTPs or store private keys to prove identity.",optionExplanations:["This describes disk encryption, not a security token.","Tokens supplement authentication factors, not necessarily replace all biometrics.","This describes IDS/IPS, not a security token.","Correct — tokens generate or store OTPs or keys to prove identity."]},
  {id:73,domain:G,question:"Which of the following BEST describes the concept of 'need to know'?",options:["Users should only access information required for their specific task","All users in a role share the same access level","Users should have the minimum permissions for their job","Administrators can override all access restrictions"],answer:0,explanation:"Need to know means even if you have clearance, you should only access information you specifically require for a task.",optionExplanations:["Correct — need to know restricts access to what's necessary for a task.","Shared role-based access describes RBAC, a related but different concept.","Minimum permissions for a job describes least privilege, a related concept.","Unrestricted admin override would violate both principles."]},
  {id:74,domain:G,question:"A company wants to ensure no single administrator can access a key alone. Which concept applies?",options:["Key escrow","Least privilege","Dual control","Separation of duties"],answer:2,explanation:"Dual control requires two authorized individuals to be present for a sensitive operation, like accessing a cryptographic key.",optionExplanations:["Key escrow holds keys with a third party for recovery, not dual access.","Least privilege limits permissions but doesn't require two people present.","Correct — dual control requires two people simultaneously for a sensitive action.","Separation of duties splits tasks among people, without requiring simultaneous presence."]},
  {id:75,domain:G,question:"Which of the following is NOT a goal of information security?",options:["Confidentiality","Availability","Integrity","Profitability"],answer:3,explanation:"The CIA triad covers Confidentiality, Integrity, and Availability. Profitability is a business goal, not an information security goal.",optionExplanations:["Confidentiality is the C in the CIA triad.","Availability is the A in the CIA triad.","Integrity is the I in the CIA triad.","Correct — profitability is a business goal, not a security goal."]},
  {id:76,domain:T,question:"Which type of malware disguises itself as legitimate software?",options:["Ransomware","Worm","Trojan","Virus"],answer:2,explanation:"A Trojan masquerades as legitimate software to trick users into installing it.",optionExplanations:["Ransomware encrypts data and demands payment; it is a separate category.","A worm self-replicates without needing a host program.","Correct — a Trojan appears legitimate but carries a malicious payload.","A virus attaches to a host file and replicates on execution."]},
  {id:77,domain:T,question:"What is a rootkit?",options:["Encrypting files for ransom payment","Self-replicating malware spread via email","Hiding its presence to enable attacker access","A port-scanning reconnaissance utility"],answer:2,explanation:"Rootkits hide malicious code and provide persistent privileged access while evading detection.",optionExplanations:["This describes ransomware, not a rootkit.","This describes a worm, not a rootkit.","Correct — a rootkit conceals itself and gives attackers persistent access.","This describes a reconnaissance tool, not a rootkit."]},
  {id:78,domain:T,question:"Which attack targets the DNS system to redirect users to malicious websites?",options:["Session hijacking","DNS poisoning","Phishing","ARP spoofing"],answer:1,explanation:"DNS poisoning (cache poisoning) injects malicious records into a DNS cache, redirecting users to attacker-controlled sites.",optionExplanations:["Session hijacking steals an authenticated session token.","Correct — DNS poisoning corrupts cache entries to redirect users.","Phishing tricks users via messages; it doesn't modify DNS.","ARP spoofing maps an attacker's MAC to an IP on a LAN."]},
  {id:79,domain:T,question:"A user receives an email appearing to be from their bank asking them to click a link and verify their account. This is MOST likely:",options:["Smishing","Whaling","Phishing","Vishing"],answer:2,explanation:"A deceptive email impersonating a trusted entity to steal credentials is a phishing attack.",optionExplanations:["Smishing uses SMS text messages, not email.","Whaling targets high-profile executives specifically.","Correct — a deceptive email impersonating a trusted entity is phishing.","Vishing uses phone calls, not email."]},
  {id:80,domain:T,question:"What is ransomware?",options:["Capturing keystrokes to steal credentials","Encrypting files and demanding payment","Self-replicating malware via removable media","Hiding at the kernel level for persistence"],answer:1,explanation:"Ransomware encrypts victim data and demands a ransom (often cryptocurrency) in exchange for the decryption key.",optionExplanations:["This describes a keylogger, not ransomware.","Correct — ransomware encrypts data and extorts payment for the key.","This describes a worm, not ransomware.","This describes a rootkit, not ransomware."]},
  {id:81,domain:T,question:"Which social engineering technique involves an attacker pretending to be an IT support technician to gain access?",options:["Phishing","Pretexting","Tailgating","Baiting"],answer:1,explanation:"Pretexting creates a fabricated scenario (a pretext) to manipulate a target into revealing information or granting access.",optionExplanations:["Phishing is conducted via deceptive email, not direct impersonation.","Correct — pretexting fabricates a scenario to manipulate a target.","Tailgating is physically following someone through a secure entry.","Baiting uses physical media or offers to lure victims."]},
  {id:82,domain:T,question:"What is a SQL injection attack?",options:["Flooding a server with connection requests","Appending malicious code to executables","Injecting malicious SQL into input fields","Intercepting database traffic on the network"],answer:2,explanation:"SQL injection inserts malicious SQL statements into unvalidated input fields to manipulate or extract database data.",optionExplanations:["This describes a denial-of-service attack, not SQL injection.","This describes a file-infecting virus, not SQL injection.","Correct — SQL injection exploits unvalidated input to run arbitrary SQL.","This describes a man-in-the-middle attack, not SQL injection."]},
  {id:83,domain:T,question:"Which of the following is a characteristic of an Advanced Persistent Threat (APT)?",options:["Targeting consumer mobile devices only","Relying only on phishing emails","A long-term, stealthy nation-state intrusion","A single opportunistic attack using public tools"],answer:2,explanation:"APTs are prolonged, targeted attacks, often state-sponsored, focused on espionage or sabotage with minimal noise.",optionExplanations:["APTs target governments and enterprises, not just consumer devices.","APTs use many techniques beyond phishing, including zero-days.","Correct — APTs are prolonged, stealthy intrusions often tied to nation-states.","APTs are persistent and targeted, unlike opportunistic single attempts."]},
  {id:84,domain:T,question:"What is the purpose of a botnet?",options:["Archiving stolen data in the cloud","Encrypting command-and-control traffic","Providing secure remote access tunnels","Coordinating attacks via infected systems"],answer:3,explanation:"A botnet is a network of compromised computers (bots) controlled by a command-and-control server for attacks.",optionExplanations:["Data archiving isn't a botnet's primary purpose.","Encrypting C2 traffic is an evasion technique, not the botnet's purpose.","This describes a VPN, not a botnet.","Correct — a botnet gives attackers infected systems to launch attacks."]},
  {id:85,domain:T,question:"Which attack type exploits unvalidated user input to execute scripts in a victim's browser?",options:["Buffer overflow","CSRF","SQL injection","Cross-site scripting (XSS)"],answer:3,explanation:"XSS injects malicious scripts into web pages viewed by other users, executing in their browser context.",optionExplanations:["Buffer overflow corrupts memory, not browser script injection.","CSRF tricks a browser into unauthorized requests, not script injection.","SQL injection targets database queries, not browser scripts.","Correct — XSS injects malicious scripts that execute in victims' browsers."]},
  {id:86,domain:T,question:"What does a keylogger do?",options:["Records keystrokes to capture credentials","Restricting keyboard input access","Encrypting keyboard input before the OS","Tracking keyboard firmware version history"],answer:0,explanation:"A keylogger captures every keystroke made by the user, allowing attackers to steal passwords and sensitive information.",optionExplanations:["Correct — keyloggers capture keystrokes to steal credentials and data.","This describes input access policy, not keylogger behavior.","Encrypting input would defeat a keylogger; real keyloggers capture plaintext.","This describes firmware tracking, not keylogger behavior."]},
  {id:87,domain:T,question:"What is a watering hole attack?",options:["Leaving infected USB drives in public","Attacking water treatment control systems","Sending personalized deceptive emails","Compromising a site the targets visit"],answer:3,explanation:"A watering hole attack compromises a website the target group regularly visits, infecting them when they browse it.",optionExplanations:["This describes a baiting attack, not a watering hole.","This describes ICS/critical infrastructure sabotage, not a watering hole.","This describes spear phishing, not a watering hole.","Correct — a watering hole attack infects a site the targets regularly visit."]},
  {id:88,domain:T,question:"What is the primary goal of a DDoS (Distributed Denial of Service) attack?",options:["Establishing a long-term covert foothold","Overwhelming a service with traffic","Exfiltrating data via unvalidated input","Encrypting files for ransom"],answer:1,explanation:"DDoS attacks flood a target with traffic from many sources to exhaust resources and deny service to legitimate users.",optionExplanations:["This describes an APT, not DDoS.","Correct — DDoS floods a target to deny service to legitimate users.","This describes a data exfiltration attack, not DDoS.","This describes ransomware, not DDoS."]},
  {id:89,domain:T,question:"Which of the following BEST describes spear phishing?",options:["Fraudulent text messages with malicious links","Phishing tailored to a specific target","Bulk emails sent to many recipients","Deceptive phone calls impersonating support staff"],answer:1,explanation:"Spear phishing uses personalized information about the target to make the deceptive message more convincing.",optionExplanations:["This describes smishing, not spear phishing.","Correct — spear phishing personalizes the attack for a specific target.","This describes standard mass phishing, not spear phishing.","This describes vishing, not spear phishing."]},
  {id:90,domain:T,question:"What is a zero-day exploit?",options:["A high-volume traffic flood attack","Targeting an unpatched, unknown vulnerability","Deployed the same day software releases","Publicly releasing exploit code at disclosure"],answer:1,explanation:"A zero-day exploit attacks a vulnerability unknown to the vendor — there are zero days of warning or patching time.",optionExplanations:["This describes a DoS attack, not a zero-day.","Correct — a zero-day targets a vulnerability unknown to the vendor.","Timing relative to a release date doesn't define a zero-day.","Public release at disclosure describes a proof-of-concept, not the zero-day itself."]},
  {id:91,domain:T,question:"Which of the following BEST describes a man-in-the-browser attack?",options:["A fake bank website","Physically intercepting communications between users","Malware altering browser transactions in real time","Covertly logging browsing history"],answer:2,explanation:"Man-in-the-browser malware modifies web transactions inside the browser after authentication, often targeting banking.",optionExplanations:["This describes phishing, not man-in-the-browser.","This describes a traditional MITM attack, not browser malware.","Correct — man-in-the-browser malware alters transactions inside the browser.","This describes spyware, not man-in-the-browser."]},
  {id:92,domain:T,question:"What is credential stuffing?",options:["Creating weak, predictable passwords","Reusing stolen credentials across many sites","Trying every combination on one account","Embedding SQL syntax in login fields"],answer:1,explanation:"Credential stuffing reuses breached credential lists against many sites, exploiting password reuse.",optionExplanations:["This is weak password hygiene, not credential stuffing.","Correct — credential stuffing reuses breached credentials across many sites.","This describes a brute-force attack, not credential stuffing.","This describes SQL injection, not credential stuffing."]},
  {id:93,domain:T,question:"Which type of threat actor is MOST motivated by financial gain?",options:["Script kiddie","Cybercriminal","Hacktivist","Nation-state actor"],answer:1,explanation:"Cybercriminals are primarily motivated by financial gain through ransomware, fraud, or data theft.",optionExplanations:["Script kiddies seek notoriety or thrill, rarely for profit.","Correct — cybercriminals seek financial gain through fraud and ransomware.","Hacktivists are motivated by ideology, not financial gain.","Nation-state actors pursue espionage or geopolitical goals."]},
  {id:94,domain:T,question:"What is a buffer overflow attack?",options:["Embedding malicious JavaScript in a web page","Intercepting traffic between client and server","Overwriting memory past a buffer's limit","Flooding a server with UDP packets"],answer:2,explanation:"Buffer overflows occur when a program writes beyond allocated memory, potentially allowing code execution.",optionExplanations:["This describes XSS, not a buffer overflow.","This describes a man-in-the-middle attack, not a buffer overflow.","Correct — a buffer overflow writes past a buffer, corrupting adjacent memory.","This describes a UDP flood DoS attack, not a buffer overflow."]},
  {id:95,domain:T,question:"Which of the following is an indicator of a phishing email? (Choose the BEST answer)",options:["A properly formatted signature block","Digitally signed with S/MIME encryption","Urgent language requesting credentials via a link","Appears to come from a known colleague"],answer:2,explanation:"Urgency and requests to click links and provide credentials are classic phishing red flags.",optionExplanations:["A signature block can be easily copied or spoofed.","Signed and encrypted emails are unusual for phishing but not impossible.","Correct — urgency plus a credential request via a link is a classic red flag.","Emails can still be phishing even from an apparently known contact."]},
  {id:96,domain:T,question:"What is a logic bomb?",options:["Recording screen activity and user input","Code that triggers on a specific condition","Flooding a target with traffic","Self-replicating malware spreading via network shares"],answer:1,explanation:"A logic bomb lies dormant until a specific trigger (date, event, action) activates the malicious payload.",optionExplanations:["This describes spyware or a RAT, not a logic bomb.","Correct — a logic bomb stays dormant until a specific trigger fires.","This describes a DoS tool, not a logic bomb.","This describes a worm, not a logic bomb."]},
  {id:97,domain:T,question:"What type of malware conceals itself and steals data over an extended period without detection?",options:["Spyware","Worm","Ransomware","Virus"],answer:0,explanation:"Spyware covertly monitors user activity and exfiltrates data without the user's knowledge.",optionExplanations:["Correct — spyware silently monitors and exfiltrates user activity.","Worms focus on propagation, not stealth data collection.","Ransomware announces itself with a ransom demand.","Viruses replicate via files; they aren't designed for stealth data theft."]},
  {id:98,domain:T,question:"Which of the following describes a vishing attack?",options:["A phishing attack conducted over the phone","A phishing attack delivered via email","A phishing attack using SMS messages","A phishing attack through social media"],answer:0,explanation:"Vishing (voice phishing) uses telephone calls to manipulate victims into revealing sensitive information.",optionExplanations:["Correct — vishing uses phone calls to steal information.","Email phishing is simply called phishing.","SMS-based phishing is smishing.","Social media phishing is a form of social engineering, not vishing."]},
  {id:99,domain:T,question:"What is the purpose of a threat intelligence feed?",options:["Provisioning user account access rights","Encrypting data at rest and in transit","Providing real-time data on known threats","Scanning endpoints and quarantining malware"],answer:2,explanation:"Threat intelligence feeds provide up-to-date data on threats, attacker TTPs, malware hashes, malicious IPs, and IOCs.",optionExplanations:["This describes IAM, not a threat intelligence feed.","This describes encryption tools, not a threat intelligence feed.","Correct — threat intel feeds supply IOCs, TTPs, and threat actor data.","This describes EDR/antivirus, not a threat intelligence feed."]},
  {id:100,domain:T,question:"Which of the following BEST describes a supply chain attack?",options:["Compromising a vendor to inject malware","Exfiltrating data via misconfigured cloud storage","Physically tampering with hardware in transit","Phishing a supplier's employees for credentials"],answer:0,explanation:"Supply chain attacks compromise trusted third-party software or hardware before it reaches the target organization.",optionExplanations:["Correct — supply chain attacks compromise a trusted vendor before delivery.","This describes a cloud misconfiguration breach, not a supply chain attack.","This describes physical sabotage, not a software supply chain attack.","This may be a preliminary step, but not the defining supply chain compromise."]},
  {id:101,domain:T,question:"What is typosquatting?",options:["Inserting malicious scripts or backdoors directly into the source code of a legitimate website","Injecting forged DNS responses into a resolver's cache to redirect traffic to attacker-controlled IP addresses","Stealing authenticated browser session tokens to impersonate a logged-in user without knowing their credentials","Registering domains with common misspellings of legitimate sites to deceive users"],answer:3,explanation:"Typosquatting registers domains like 'googlle.com' hoping users mistype a URL and land on the malicious site.",optionExplanations:["Inserting malicious scripts directly into a legitimate website's code describes a web application compromise or watering hole attack.","Injecting forged DNS responses to redirect traffic describes DNS cache poisoning or spoofing, not typosquatting.","Stealing authenticated session tokens to impersonate a logged-in user describes session hijacking, not typosquatting.","Typosquatting exploits common typographical mistakes to register deceptive domain names that mimic legitimate ones."]},
  {id:102,domain:T,question:"Which term describes when an attacker pretends to be an executive in an email to trick employees into transferring funds?",options:["Whaling that targets senior executives themselves as the phishing victims","Business email compromise (BEC) impersonating an executive to authorize fraud","Spear phishing that targets a specific, carefully researched individual employee","Smishing that delivers fraudulent text messages to a victim's phone"],answer:1,explanation:"BEC (Business Email Compromise) specifically targets organizations by impersonating executives to authorize fraudulent transfers.",optionExplanations:["Whaling is phishing that targets executives as the victims, not impersonating them to attack others.","BEC impersonates executives or vendors by email to manipulate employees into making unauthorized financial transfers.","Spear phishing is a personalized attack on a specific target; BEC is a subset that specifically targets financial fraud via executive impersonation.","Smishing relies on SMS text messages; BEC is specifically an email-based financial fraud scheme."]},
  {id:103,domain:T,question:"What is an indicator of compromise (IoC)?",options:["A documented list of pre-approved firewall rules governing allowed network traffic","A report generated by an automated tool listing discovered system vulnerabilities","A specific category or family of malicious software designed to cause harm","Evidence suggesting a system has been breached or is under attack"],answer:3,explanation:"IoCs are artifacts like suspicious IPs, malware hashes, or unusual log entries that indicate a possible compromise.",optionExplanations:["Approved firewall rules are security configuration items used to permit or deny traffic, not compromise indicators.","Vulnerability scan results describe potential weaknesses in a system; IoCs indicate an attack that has actually occurred.","Malware is the threat itself; IoCs are the evidence artifacts left behind by malware or attacker activity.","IoCs are forensic artifacts — IP addresses, file hashes, domain names, or behavioral patterns — indicating compromise."]},
  {id:104,domain:T,question:"What is shimming in the context of malware?",options:["A software compatibility shim technique that replaces deprecated API calls with updated equivalents for newer operating systems","A network bridging technique that connects two separate Layer 2 network segments by forwarding frames between physical interfaces","Malware that inserts itself between a legitimate application and its dependencies to intercept calls","A steganography technique that conceals secret data within digital image files by manipulating least-significant bits of pixel values"],answer:2,explanation:"Shimming malware inserts a malicious layer between an application and the OS/API to intercept function calls.",optionExplanations:["This describes a legitimate software compatibility layer, not malware; shimming as malware specifically intercepts calls to steal data or inject code.","Bridging connects network segments at Layer 2 and is a networking concept unrelated to malware shimming.","Shimming inserts malicious code as a compatibility layer to intercept API calls between applications and system libraries.","Steganography hides data inside media files; shimming malware instead inserts itself as an intermediary to intercept API calls."]},
  {id:105,domain:T,question:"Which of the following BEST describes a fileless malware attack?",options:["Malware that automatically deletes its own executable file immediately after it finishes running","Malware whose malicious code is concealed inside the pixel data of ordinary image files","Malware that runs entirely in memory without writing files to disk","Malware that conceals its executable files within hidden or disguised folders on the disk"],answer:2,explanation:"Fileless malware operates in RAM using legitimate system tools (e.g., PowerShell), leaving no files on disk.",optionExplanations:["Self-deleting malware still touches the disk before removing itself; fileless malware never writes files to disk in the first place.","Concealing code inside images describes steganography-based malware delivery; fileless malware avoids the disk entirely rather than hiding within a file type.","Fileless malware runs in memory leveraging tools like PowerShell or WMI, evading file-based antivirus detection.","Hiding files on disk is traditional stealth malware behavior; fileless malware specifically avoids writing any files to disk at all."]},
  {id:106,domain:T,question:"What is a rainbow table attack?",options:["Systematically testing character combinations against wireless network authentication to recover the WPA2 pre-shared key","Capturing hashed authentication credentials as they traverse the network using a packet capture tool","Submitting randomly generated password attempts against a live login form at high speed to gain unauthorized access","Using precomputed hash values to reverse password hashes faster than brute force"],answer:3,explanation:"Rainbow tables are precomputed lists of plaintext-to-hash mappings, used to quickly reverse unsalted password hashes.",optionExplanations:["Systematically testing character combinations against wireless authentication describes a WPA2 brute force attack, not a rainbow table attack.","Capturing hashed credentials on the wire is a network sniffing attack; rainbow tables are used offline after capturing hashes.","Submitting randomly generated passwords against a live login form is an online brute force attack.","Rainbow tables use precomputed hash chains to find the plaintext behind a hash without recomputing each guess."]},
  {id:107,domain:T,question:"Which type of attack sends unsolicited Bluetooth messages to nearby devices?",options:["Bluejacking","Bluesnarfing","Bluebugging","Evil twin"],answer:0,explanation:"Bluejacking sends unsolicited messages (like contact cards) to nearby Bluetooth-enabled devices.",optionExplanations:["Bluejacking sends unsolicited messages to nearby Bluetooth devices — generally annoying but not data-stealing.","Bluesnarfing illegally accesses and downloads data from a Bluetooth device without permission.","Bluebugging takes full control of a Bluetooth device, including calls and messages — more severe than bluejacking.","Evil twin is a rogue Wi-Fi AP attack, not a Bluetooth attack."]},
  {id:108,domain:T,question:"What is a cross-site request forgery (CSRF) attack?",options:["Injecting malicious scripts into web pages viewed by other users","Injecting malicious SQL statements into database queries by submitting unsanitized input through web application form fields","Tricking a user's browser into making unauthorized requests to a site where they are authenticated","Capturing authentication tokens from network traffic by using ARP spoofing to redirect sessions through an attacker-controlled host"],answer:2,explanation:"CSRF tricks an authenticated user's browser into making unwanted requests to a trusted site, leveraging existing session tokens.",optionExplanations:["Injecting malicious scripts is XSS, not CSRF.","This describes SQL injection, not CSRF; CSRF exploits a user's authenticated browser session rather than manipulating database queries.","CSRF forces an authenticated user's browser to perform actions on a site they're logged into without their knowledge.","This describes session hijacking via ARP spoofing, not CSRF; CSRF abuses existing authenticated sessions rather than stealing tokens from the network."]},
  {id:109,domain:T,question:"What does 'pivoting' mean in a penetration test?",options:["Deleting event logs, removing attacker tools, and clearing shell history to prevent forensic reconstruction of post-exploitation activity","Switching an attacker's methodology from external perimeter reconnaissance to exploiting services on the internal corporate network","Exploiting local kernel vulnerabilities or misconfigured SUID binaries to elevate from a standard user to root on a single host","Using a compromised host as a launching point to attack other systems on the network"],answer:3,explanation:"Pivoting uses a compromised system as a relay to reach and attack otherwise inaccessible network segments.",optionExplanations:["This describes anti-forensics and covering tracks, a separate post-exploitation phase; pivoting is about reaching new network targets, not concealing activity.","Changing attack methodology describes a general strategy shift, not specifically pivoting; pivoting requires using a compromised host as the transit point.","This describes privilege escalation on one system, a separate step; pivoting moves laterally to other systems using an already-compromised host as a launchpad.","Pivoting leverages a compromised host to tunnel traffic and reach internal hosts not directly accessible from the internet."]},
  {id:110,domain:T,question:"Which of the following BEST describes a man-in-the-middle (MITM) attack prevention?",options:["Enabling two-factor authentication only","Updating firewall rules","Using complex passwords","Implementing certificate pinning and mutual TLS"],answer:3,explanation:"Certificate pinning and mutual TLS ensure both parties verify each other's certificates, preventing MITM interception.",optionExplanations:["2FA verifies identity at login but does not prevent in-transit communication interception.","Firewall rules control network traffic flow but do not prevent MITM attacks within allowed traffic streams.","Complex passwords protect against credential attacks but not MITM interception of traffic.","Certificate pinning and mutual TLS prevent MITM by requiring both client and server to authenticate certificates."]},
  {id:111,domain:T,question:"Which of the following is a passive reconnaissance technique?",options:["Attempting to log in with default credentials","Researching a company's public website and social media","Port scanning the target","Sending phishing emails"],answer:1,explanation:"Passive reconnaissance gathers information without directly interacting with target systems (OSINT, public records).",optionExplanations:["Attempting logins is active and may trigger alarms.","Reviewing public websites and social media is OSINT — passive, with no direct interaction with target systems.","Port scanning directly probes target systems, making it active reconnaissance.","Phishing is an active attack, not reconnaissance."]},
  {id:112,domain:T,question:"What is the purpose of a honeypot?",options:["Provide encrypted communication tunnels for remote users connecting to the corporate network","Lure attackers to a decoy system to observe and analyze their techniques","Inspect inbound and outbound network packets and automatically block sessions matching malicious threat signatures","Maintain redundant copies of production data in an isolated repository protected against accidental deletion or corruption"],answer:1,explanation:"Honeypots are intentionally vulnerable decoy systems designed to attract attackers and study their behavior.",optionExplanations:["Providing encrypted tunnels for remote users describes a VPN solution, not a honeypot.","A honeypot is a decoy resource designed to detect, distract, and study attackers without risk to real systems.","Inspecting packets and blocking malicious sessions describes an intrusion prevention system, not a honeypot.","Maintaining redundant data copies describes a backup repository; honeypots are decoy systems, not storage resources."]},
  {id:113,domain:T,question:"An attacker intercepts encrypted HTTPS traffic for later decryption. What type of attack is this?",options:["SSL stripping","Capture now, decrypt later","Pass-the-hash","Replay attack"],answer:1,explanation:"'Harvest now, decrypt later' (capture now, decrypt later) saves encrypted traffic hoping to decrypt it when keys are available or quantum computing matures.",optionExplanations:["SSL stripping downgrades HTTPS to HTTP in real time; it doesn't capture for later decryption.","'Capture now, decrypt later' stockpiles encrypted data to decrypt once decryption capability becomes available.","Pass-the-hash steals NTLM hashes for authentication without knowing the plaintext.","A replay attack resends captured credentials or tokens; it does not store encrypted traffic for future decryption."]},
  {id:114,domain:T,question:"What is tailgating in physical security?",options:["Planting an infected USB drive in a parking lot hoping an employee plugs it in","Following an authorized person through a secure door without authentication","Covertly monitoring an employee's computer activity from a remote location without their knowledge","Sending a fraudulent email that impersonates a trusted colleague to manipulate the recipient"],answer:1,explanation:"Tailgating (piggybacking) bypasses physical access controls by following an authorized person through a secured entry.",optionExplanations:["Planting a USB drive to lure someone into plugging it in describes a baiting attack, not tailgating.","Tailgating exploits social courtesy to physically bypass access controls without badging in.","Remotely monitoring a computer is a cyber surveillance technique, not a physical tailgating attack.","Impersonating a colleague by email describes phishing or business email compromise, not a physical security bypass."]},
  {id:115,domain:T,question:"Which of the following BEST describes a logic bomb?",options:["Malware that encrypts victim files using a symmetric key and demands cryptocurrency ransom for the decryption key","Code that executes a malicious payload when a specific condition is met","Self-replicating malware that propagates between Bluetooth-enabled devices without requiring user interaction","A destructive virus that immediately overwrites or deletes files on the host system upon execution"],answer:1,explanation:"Logic bombs trigger on conditions like a date, time, or event — e.g., deleting files if an employee account is disabled.",optionExplanations:["Malware encrypting files for cryptocurrency ransom describes ransomware; a logic bomb's defining trait is conditional execution, not encryption.","A logic bomb stays dormant until a specific trigger condition is met before executing its payload.","Malware spreading autonomously between Bluetooth-enabled devices describes a Bluetooth worm, not a logic bomb.","A virus that immediately destroys files upon execution is a wiper; logic bombs delay their action until a trigger event."]},
  {id:116,domain:T,question:"An employee copies sensitive company data to a personal USB drive before leaving. What type of threat is this?",options:["Insider threat","Zero-day attack","Supply chain attack","External threat"],answer:0,explanation:"Malicious or negligent behavior by an internal employee or contractor constitutes an insider threat.",optionExplanations:["An insider threat involves an employee, contractor, or trusted person who misuses their access.","Zero-day attacks exploit unknown vulnerabilities in software; this is data theft by an insider.","Supply chain attacks compromise vendors or products before delivery; this is internal data theft.","External threats originate outside the organization; this employee is an insider."]},
  {id:117,domain:T,question:"What is a pharming attack?",options:["Redirecting users from legitimate websites to malicious ones via DNS manipulation","Distributing large volumes of deceptive emails impersonating trusted brands to trick recipients into revealing credentials","Creating a rogue wireless access point with the same SSID as a legitimate network to intercept user traffic","Embedding malicious code in email attachments that executes when the recipient opens the file or enables macros"],answer:0,explanation:"Pharming corrupts DNS settings or poisons caches to redirect users to malicious sites even when they type the correct URL.",optionExplanations:["Pharming redirects traffic at the DNS level, so even correct URLs resolve to attacker-controlled sites.","Distributing deceptive emails impersonating trusted brands describes mass phishing, not pharming.","Creating a rogue AP with the same SSID as a legitimate network describes an evil twin attack.","Embedding malicious code in email attachments that executes when opened describes email-based malware delivery."]},
  {id:118,domain:T,question:"Which of the following is an example of a brute force attack?",options:["Trying every possible password combination until one works","Manipulating a help desk employee into resetting an account password by fabricating a plausible identity","Stealing an authenticated browser session cookie from network traffic to impersonate a logged-in user","Inserting malicious SQL syntax into a web application's login field to bypass authentication database queries"],answer:0,explanation:"A brute force attack systematically tries all possible combinations of characters until the correct password is found.",optionExplanations:["Brute force exhaustively tries every possible password combination until finding the correct one.","Manipulating a help desk employee to reset an account describes social engineering.","Stealing an authenticated session cookie from traffic to impersonate a user describes session hijacking.","Inserting malicious SQL into a login field to bypass authentication describes SQL injection, not brute force."]},
  {id:119,domain:T,question:"What distinguishes a worm from a virus?",options:["Worms must attach to an executable host file to spread; viruses propagate autonomously across network connections without a host","Worms self-replicate and spread independently; viruses need to attach to a host file","Viruses spread automatically over networks; worms require user interaction","Worms require a host file to spread; viruses do not"],answer:1,explanation:"Worms are self-contained and self-propagating; viruses require a host file and user action to spread.",optionExplanations:["This reverses the definitions; worms spread autonomously without a host file, while viruses require a host file to attach to and propagate.","A worm self-replicates and propagates across networks without user interaction or a host file.","Viruses require user action (opening an infected file); worms spread autonomously.","It is viruses that require a host file; worms are self-contained."]},
  {id:120,domain:T,question:"Which attack technique uses multiple systems to overwhelm a target?",options:["APT","Spear phishing","DDoS","MITM"],answer:2,explanation:"DDoS (Distributed Denial of Service) uses botnets of many systems to flood a target with traffic.",optionExplanations:["APTs are prolonged stealthy intrusions; they don't necessarily use volume-based flooding.","Spear phishing is a targeted social engineering email attack, not a multi-system flooding attack.","DDoS distributes the attack across many compromised systems to amplify the flood against a single target.","MITM intercepts communication between two parties; it doesn't require many attacking systems."]},
  {id:121,domain:T,question:"What does OSINT stand for and what is its primary use in security?",options:["Online Security Intelligence — a practice limited to monitoring dark web criminal forums","Operational Security Intelligence — a discipline focused on protecting classified operational data","Open Source Intelligence — gathering information from public sources for reconnaissance","On-Site Intelligence — a discipline focused exclusively on physical penetration testing engagements"],answer:2,explanation:"OSINT collects intelligence from publicly available sources (social media, websites, job postings) for reconnaissance.",optionExplanations:["OSINT can include monitoring the dark web, but it is not limited to online sources, and this is not what the acronym stands for.","Operational Security (OPSEC) is about protecting sensitive operational information, which is the opposite of OSINT's information-gathering purpose.","OSINT (Open Source Intelligence) uses publicly available data to learn about targets before attacking.","On-Site Intelligence is not a recognized security term; OSINT does not stand for this and is not limited to physical testing."]},
  {id:122,domain:T,question:"Which of the following is a characteristic of spyware?",options:["Repeatedly displays intrusive, unwanted advertisements to the user without their consent","Encrypts a victim's files and demands payment in exchange for the decryption key","Covertly monitors user activity and transmits data to a third party","Automatically replicates itself across network shares to infect additional connected systems"],answer:2,explanation:"Spyware secretly observes user behavior, keystroke logging, browsing, and transmits data to the attacker.",optionExplanations:["Displaying unwanted ads describes adware, which is a distinct category from covert data-collecting spyware.","Encrypting files and demanding payment describes ransomware, not spyware.","Spyware covertly collects and exfiltrates user information such as credentials, browsing history, and personal data.","Self-replication across a network describes worm behavior, not spyware's covert monitoring function."]},
  {id:123,domain:T,question:"A SCADA system at a power plant is attacked, causing physical damage to turbines. Which type of attack is this?",options:["Ransomware attack","Cyber-physical attack","DDoS attack","Phishing attack"],answer:1,explanation:"Cyber-physical attacks target industrial control systems (ICS/SCADA) to cause physical harm to equipment or infrastructure.",optionExplanations:["Ransomware encrypts data for extortion; it does not typically cause physical equipment damage.","A cyber-physical attack uses cyber means to cause real-world physical consequences, as seen in Stuxnet.","DDoS disrupts availability of services; it does not directly cause physical equipment damage.","Phishing is a social engineering technique to steal credentials, not to damage physical equipment."]},
  {id:124,domain:T,question:"What is the difference between a vulnerability and an exploit?",options:["An exploit is a weakness; a vulnerability is the attack tool","A vulnerability is the attack tool leveraged to compromise systems; an exploit is the underlying weakness discovered by security scanners","A vulnerability is a weakness; an exploit is the code or technique that takes advantage of it","A vulnerability and an exploit are interchangeable security terms both describing the same exploitable flaw within a target system"],answer:2,explanation:"A vulnerability is the flaw (weakness); an exploit is the method or code that leverages that flaw to attack.",optionExplanations:["An exploit uses the vulnerability, not the other way around.","This reverses the definitions; a vulnerability is the weakness, and an exploit is the technique that leverages the vulnerability to cause harm.","A vulnerability is the underlying weakness in software or configuration; an exploit weaponizes that weakness.","They are not the same; a vulnerability is a weakness that exists, while an exploit is the specific code or method used to take advantage of it."]},
  {id:125,domain:T,question:"Which threat vector uses text messages to deliver phishing attacks?",options:["Vishing","Smishing","Whaling","Phishing"],answer:1,explanation:"Smishing = SMS phishing — malicious links or prompts sent via text message.",optionExplanations:["Vishing uses voice calls (phone) for phishing.","Smishing specifically uses SMS text messages to deliver phishing content.","Whaling targets executives as the victims, regardless of delivery channel.","Phishing is the general email-based version."]},
  {id:126,domain:A,question:"What is the purpose of a DMZ in network security?",options:["Encrypt traffic exchanged directly between internal users on the corporate network","Host publicly accessible services while isolating the internal network","Store backup copies of organizational data for disaster recovery purposes","Provide wireless network access to employees throughout the office building"],answer:1,explanation:"A DMZ (Demilitarized Zone) places public-facing servers between two firewalls, protecting the internal network.",optionExplanations:["Traffic encryption between internal users is provided by VPNs and TLS, not by a DMZ architecture.","A DMZ isolates public-facing services (web, email, DNS) from the internal corporate network using firewall layers.","Backup data is stored in dedicated backup repositories, not in a DMZ.","Wireless access is provided by access points and controllers, not by a DMZ."]},
];
